const WabaPhoneNumberSetupFinalization = @import("waba_phone_number_setup_finalization.zig").WabaPhoneNumberSetupFinalization;
const WabaSetupFinalization = @import("waba_setup_finalization.zig").WabaSetupFinalization;

/// The details of linking a WhatsApp Business Account to your Amazon Web
/// Services account.
pub const WhatsAppSetupFinalization = struct {
    /// An Amazon Web Services access token generated by `WhatsAppSignupCallback`
    /// and used by `WhatsAppSetupFinalization`.
    associate_in_progress_token: []const u8,

    /// Used to add a new phone number to an existing WhatsApp Business Account.
    /// This field can't be used when the `waba` field is present.
    phone_number_parent: ?[]const u8,

    /// An array of WabaPhoneNumberSetupFinalization objects containing the details
    /// of each phone number associated with the WhatsApp Business Account.
    phone_numbers: []const WabaPhoneNumberSetupFinalization,

    /// Used to create a new WhatsApp Business Account and add a phone number. This
    /// field can't be used when the `phoneNumberParent` field is present.
    waba: ?WabaSetupFinalization,

    pub const json_field_names = .{
        .associate_in_progress_token = "associateInProgressToken",
        .phone_number_parent = "phoneNumberParent",
        .phone_numbers = "phoneNumbers",
        .waba = "waba",
    };
};
